import { createHash } from 'node:crypto';
import { describe, expect, it } from 'vitest';
import {
  createCodeGraphyPluginSignature,
  createCodeGraphySettingsSignature,
} from '../../../src/extension/repoSettings/signatures';
import { createDefaultCodeGraphyRepoSettings } from '../../../src/extension/repoSettings/defaults';

function hashStableSettings(value: unknown): string {
  return createHash('sha1')
    .update(JSON.stringify(value))
    .digest('hex');
}

describe('extension/repoSettings/signatures', () => {
  it('creates a stable plugin signature in registry order', () => {
    expect(createCodeGraphyPluginSignature([
      { plugin: { id: 'codegraphy.markdown', version: '1.0.0' } },
      { plugin: { id: 'codegraphy.typescript', version: '2.0.0' } },
    ])).toBe('codegraphy.markdown@1.0.0|codegraphy.typescript@2.0.0');
  });

  it('changes the plugin signature when the plugin order changes', () => {
    expect(createCodeGraphyPluginSignature([
      { plugin: { id: 'codegraphy.typescript', version: '2.0.0' } },
      { plugin: { id: 'codegraphy.markdown', version: '1.0.0' } },
    ])).toBe('codegraphy.typescript@2.0.0|codegraphy.markdown@1.0.0');
  });

  it('returns null when no plugins are registered', () => {
    expect(createCodeGraphyPluginSignature([])).toBeNull();
  });

  it('creates the same settings signature for equivalent visibility records regardless of key order', () => {
    const base = createDefaultCodeGraphyRepoSettings();
    const reordered = createDefaultCodeGraphyRepoSettings();

    base.nodeVisibility = { file: true, folder: false, package: false };
    reordered.nodeVisibility = { package: false, file: true, folder: false };

    expect(createCodeGraphySettingsSignature(base)).toBe(
      createCodeGraphySettingsSignature(reordered),
    );
  });

  it('does not invalidate the stored index when only disabled plugins change', () => {
    const enabledState = createDefaultCodeGraphyRepoSettings();
    const disabledState = createDefaultCodeGraphyRepoSettings();

    enabledState.disabledPlugins = [];
    disabledState.disabledPlugins = ['codegraphy.python'];

    expect(createCodeGraphySettingsSignature(enabledState)).toBe(
      createCodeGraphySettingsSignature(disabledState),
    );
  });

  it('changes the settings signature when tracked scalar and list settings change', () => {
    const base = createDefaultCodeGraphyRepoSettings();
    const changed = createDefaultCodeGraphyRepoSettings();

    changed.maxFiles = 900;
    changed.include = ['src/**/*.ts'];
    changed.filterPatterns = ['**/*.png'];
    changed.pluginOrder = ['codegraphy.typescript'];

    expect(createCodeGraphySettingsSignature(changed)).not.toBe(
      createCodeGraphySettingsSignature(base),
    );
  });

  it('hashes the exact normalized default payload for partial settings', () => {
    expect(createCodeGraphySettingsSignature({})).toBe(hashStableSettings({
      maxFiles: null,
      respectGitignore: true,
      depthMode: false,
      depthLimit: 1,
      include: [],
      filterPatterns: [],
      pluginOrder: [],
      nodeVisibility: [],
      edgeVisibility: [],
    }));
  });

  it('hashes the exact normalized payload for explicit settings values', () => {
    expect(createCodeGraphySettingsSignature({
      maxFiles: 250,
      respectGitignore: false,
      depthMode: true,
      depthLimit: 4,
      include: ['src/**/*.ts'],
      filterPatterns: ['**/*.png'],
      pluginOrder: ['codegraphy.typescript'],
      nodeVisibility: { package: false, file: true },
      edgeVisibility: { import: false, call: true },
    })).toBe(hashStableSettings({
      maxFiles: 250,
      respectGitignore: false,
      depthMode: true,
      depthLimit: 4,
      include: ['src/**/*.ts'],
      filterPatterns: ['**/*.png'],
      pluginOrder: ['codegraphy.typescript'],
      nodeVisibility: [
        ['file', true],
        ['package', false],
      ],
      edgeVisibility: [
        ['call', true],
        ['import', false],
      ],
    }));
  });
});

import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { afterEach, describe, expect, it } from 'vitest';
import {
  createDefaultCodeGraphyRepoMeta,
  getCodeGraphyRepoMetaPath,
  readCodeGraphyRepoMeta,
  writeCodeGraphyRepoMeta,
} from '../../../src/extension/repoSettings/meta';

function createTempWorkspace(): string {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'codegraphy-repo-meta-'));
}

describe('extension/repoSettings/meta', () => {
  const tempDirectories: string[] = [];

  afterEach(() => {
    for (const directory of tempDirectories.splice(0)) {
      fs.rmSync(directory, { recursive: true, force: true });
    }
  });

  it('returns defaults when .codegraphy/meta.json is missing', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(createDefaultCodeGraphyRepoMeta());
  });

  it('returns fresh default metadata values on each call', () => {
    const first = createDefaultCodeGraphyRepoMeta();
    const second = createDefaultCodeGraphyRepoMeta();

    expect(second).toEqual(first);
    expect(second).not.toBe(first);
    expect(second.pendingChangedFiles).not.toBe(first.pendingChangedFiles);
  });

  it('builds the meta path inside the repo-local .codegraphy directory', () => {
    expect(getCodeGraphyRepoMetaPath('/workspace/project')).toBe(
      path.join('/workspace/project', '.codegraphy', 'meta.json'),
    );
  });

  it('always uses meta.json as the persisted metadata filename', () => {
    expect(path.basename(getCodeGraphyRepoMetaPath('/workspace/project'))).toBe('meta.json');
  });

  it('writes and reads .codegraphy/meta.json', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const meta = {
      version: 1 as const,
      lastIndexedAt: '2026-04-08T19:00:00.000Z',
      lastIndexedCommit: 'abc123',
      pluginSignature: 'codegraphy.markdown@1.0.0',
      settingsSignature: 'settings-sha',
      pendingChangedFiles: ['src/index.ts'],
    };

    writeCodeGraphyRepoMeta(workspaceRoot, meta);
    writeCodeGraphyRepoMeta(workspaceRoot, meta);

    expect(fs.existsSync(getCodeGraphyRepoMetaPath(workspaceRoot))).toBe(true);
    expect(fs.readFileSync(getCodeGraphyRepoMetaPath(workspaceRoot), 'utf8')).toBe(
      `${JSON.stringify(meta, null, 2)}\n`,
    );
    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(meta);
  });

  it('merges partial persisted meta with the default fields', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(
      metaPath,
      JSON.stringify({
        lastIndexedCommit: 'abc123',
        pendingChangedFiles: ['src/app.ts'],
      }, null, 2),
      'utf8',
    );

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual({
      version: 1,
      lastIndexedAt: null,
      lastIndexedCommit: 'abc123',
      pluginSignature: null,
      settingsSignature: null,
      pendingChangedFiles: ['src/app.ts'],
    });
  });

  it('fills in an empty pendingChangedFiles list when persisted metadata omits it', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(
      metaPath,
      JSON.stringify({
        lastIndexedCommit: 'abc123',
      }, null, 2),
      'utf8',
    );

    expect(readCodeGraphyRepoMeta(workspaceRoot).pendingChangedFiles).toEqual([]);
  });

  it('falls back to defaults when meta.json is invalid', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(metaPath, '{bad json', 'utf8');

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(createDefaultCodeGraphyRepoMeta());
  });

  it('skips writes when the workspace root does not exist', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    fs.rmSync(workspaceRoot, { recursive: true, force: true });
    const meta = {
      version: 1 as const,
      lastIndexedAt: '2026-04-08T19:00:00.000Z',
      lastIndexedCommit: 'abc123',
      pluginSignature: 'codegraphy.markdown@1.0.0',
      settingsSignature: 'settings-sha',
      pendingChangedFiles: ['src/index.ts'],
    };

    expect(fs.existsSync(workspaceRoot)).toBe(false);
    writeCodeGraphyRepoMeta(workspaceRoot, meta);

    expect(fs.existsSync(getCodeGraphyRepoMetaPath(workspaceRoot))).toBe(false);
  });
});

