import { describe, expect, it } from 'vitest';
import { collectChangedKeys } from '../../../src/extension/repoSettings/storeDiff';

describe('extension/repoSettings/storeDiff', () => {
  it('returns the repo root key when primitive values change at the top level', () => {
    expect(collectChangedKeys('old', 'new')).toEqual(['codegraphy']);
  });

  it('returns the repo root key when the top level changes between an object and a primitive', () => {
    expect(collectChangedKeys({ filters: { maxFiles: 200 } }, 'new')).toEqual([
      'codegraphy',
    ]);
    expect(collectChangedKeys('old', { filters: { maxFiles: 500 } })).toEqual([
      'codegraphy',
    ]);
  });

  it('returns the current nested path when a non-object leaf changes', () => {
    expect(
      collectChangedKeys(
        { filters: { maxFiles: 200 } },
        { filters: { maxFiles: 500 } },
      ),
    ).toEqual(['filters.maxFiles']);
  });

  it('collects changed keys from both previous and next object shapes', () => {
    expect(
      collectChangedKeys(
        { graph: { depthLimit: 2, showLabels: true } },
        { graph: { showLabels: true, directionMode: 'particles' } },
      ).sort(),
    ).toEqual(['graph.depthLimit', 'graph.directionMode']);
  });

  it('returns the nested path when one side changes between an object and a primitive', () => {
    expect(
      collectChangedKeys(
        { graph: { filters: { includeGenerated: true } } },
        { graph: { filters: false } },
      ),
    ).toEqual(['graph.filters']);

    expect(
      collectChangedKeys(
        { graph: { filters: false } },
        { graph: { filters: { includeGenerated: true } } },
      ),
    ).toEqual(['graph.filters']);
  });

  it('returns an empty list when nested values are unchanged', () => {
    expect(
      collectChangedKeys(
        { graph: { colors: { folder: '#123456' } } },
        { graph: { colors: { folder: '#123456' } } },
      ),
    ).toEqual([]);
  });
});

import { describe, expect, it } from 'vitest';
import {
  getNestedValue,
  hasNestedValue,
  setNestedValue,
} from '../../../src/extension/repoSettings/storeValues';

describe('extension/repoSettings/storeValues', () => {
  it('reads and reports nested values through normalized alias keys', () => {
    const settings = {
      nodeColors: { folder: '#123456' },
      filterPatterns: ['src/**'],
      timeline: { playbackSpeed: 2 },
    };

    expect(getNestedValue(settings, 'folderNodeColor')).toBe('#123456');
    expect(getNestedValue(settings, 'exclude')).toEqual(['src/**']);
    expect(getNestedValue(settings, 'timeline.playbackSpeed')).toBe(2);
    expect(getNestedValue(settings, 'timeline.maxCommits')).toBeUndefined();
    expect(getNestedValue(settings, 'exclude.0')).toBeUndefined();
    expect(getNestedValue({ timeline: 2 }, 'timeline.playbackSpeed')).toBeUndefined();
    expect(hasNestedValue(settings, 'exclude')).toBe(true);
    expect(hasNestedValue(settings, 'exclude.0')).toBe(false);
    expect(hasNestedValue({ timeline: 2 }, 'timeline.playbackSpeed')).toBe(false);
    expect(hasNestedValue(settings, 'timeline.maxCommits')).toBe(false);
  });

  it('creates missing nested objects and ignores empty keys when setting values', () => {
    const settings: Record<string, unknown> = {
      nodeColors: '#bad-shape',
    };

    setNestedValue(settings, 'folderNodeColor', '#abcdef');
    setNestedValue(settings, 'physics.chargeRange', 300);
    setNestedValue(settings, 'physics.centerForce', 0.1);
    setNestedValue(settings, '', 'ignored');

    expect(settings).toEqual({
      nodeColors: { folder: '#abcdef' },
      physics: { chargeRange: 300, centerForce: 0.1 },
    });
  });
});

import { describe, expect, it } from 'vitest';
import { createDefaultCodeGraphyRepoSettings } from '../../../src/extension/repoSettings/defaults';
import { serializeSettings } from '../../../src/extension/repoSettings/storeSerialization';

type LegacySettingsShape = ReturnType<typeof createDefaultCodeGraphyRepoSettings> & {
  exclude?: string[];
  folderNodeColor?: string;
  nodeColors?: unknown;
};

describe('extension/repoSettings/storeSerialization', () => {
  it('removes legacy fields and backfills folder node colors into nodeColors', () => {
    const settings: LegacySettingsShape = createDefaultCodeGraphyRepoSettings();
    settings.exclude = ['legacy'];
    settings.folderNodeColor = '#445566';
    settings.nodeColors = { file: '#111111' };

    const serialized = serializeSettings(settings);
    const parsed = JSON.parse(serialized) as Record<string, unknown>;

    expect(serialized.endsWith('\n')).toBe(true);
    expect(parsed.exclude).toBeUndefined();
    expect(parsed.folderNodeColor).toBeUndefined();
    expect(parsed.nodeColors).toEqual({
      file: '#111111',
      folder: '#445566',
    });
    expect(settings.exclude).toEqual(['legacy']);
    expect(settings.folderNodeColor).toBe('#445566');
  });

  it('prefers an explicit folder color over the legacy folderNodeColor alias', () => {
    const settings: LegacySettingsShape = createDefaultCodeGraphyRepoSettings();
    settings.folderNodeColor = '#445566';
    settings.nodeColors = { folder: '#123456', file: '#111111' };

    const parsed = JSON.parse(serializeSettings(settings)) as Record<string, unknown>;

    expect(parsed.nodeColors).toEqual({
      folder: '#123456',
      file: '#111111',
    });
  });

  it('writes an empty nodeColors object when the persisted value is malformed', () => {
    const settings = createDefaultCodeGraphyRepoSettings() as Omit<LegacySettingsShape, 'nodeColors'> & {
      nodeColors: unknown;
    };
    settings.nodeColors = 'invalid';
    settings.folderNodeColor = '';

    const parsed = JSON.parse(
      serializeSettings(settings as ReturnType<typeof createDefaultCodeGraphyRepoSettings>),
    ) as Record<string, unknown>;

    expect(parsed.nodeColors).toEqual({ folder: '' });
  });
});

import { describe, expect, it } from 'vitest';
import { normalizePersistedSettingsShape } from '../../../src/extension/repoSettings/storeNormalization';

describe('extension/repoSettings/storeNormalization', () => {
  it('returns an empty object for non-object persisted values', () => {
    expect(normalizePersistedSettingsShape(null)).toEqual({});
    expect(normalizePersistedSettingsShape(['legend'])).toEqual({});
    expect(normalizePersistedSettingsShape('settings')).toEqual({});
  });

  it('deduplicates filter patterns, removes exclude, and backfills legend from groups', () => {
    expect(normalizePersistedSettingsShape({
      filterPatterns: ['**/*.png', '**/*.png', 42, '**/*.tmp'],
      exclude: ['legacy'],
      groups: [{ id: 'group-1', pattern: 'src/**', color: '#123456' }],
    })).toEqual({
      filterPatterns: ['**/*.png', '**/*.tmp'],
      groups: [{ id: 'group-1', pattern: 'src/**', color: '#123456' }],
      legend: [{ id: 'group-1', pattern: 'src/**', color: '#123456' }],
    });
  });

  it('keeps an existing legend and merges folderNodeColor only when folder is missing', () => {
    expect(normalizePersistedSettingsShape({
      legend: [{ id: 'legend-1', pattern: 'tests/**', color: '#abcdef' }],
      groups: [{ id: 'legacy-group', pattern: 'src/**', color: '#123456' }],
      nodeColors: { folder: '#654321', file: '#111111' },
      folderNodeColor: '#222222',
    })).toEqual({
      legend: [{ id: 'legend-1', pattern: 'tests/**', color: '#abcdef' }],
      groups: [{ id: 'legacy-group', pattern: 'src/**', color: '#123456' }],
      nodeColors: { folder: '#654321', file: '#111111' },
      folderNodeColor: '#222222',
    });
  });

  it('creates nodeColors from folderNodeColor when the persisted shape lacks one', () => {
    expect(normalizePersistedSettingsShape({
      nodeColors: 'invalid',
      folderNodeColor: '#445566',
      filterPatterns: [],
      exclude: ['legacy'],
    })).toEqual({
      filterPatterns: [],
      folderNodeColor: '#445566',
      nodeColors: { folder: '#445566' },
    });
  });
});

